"use client";

import {
  Globe,
  House,
  LayoutGrid,
  Menu,
  Search,
  ShoppingBag,
  UserCircle2,
  X,
  type LucideIcon,
} from "lucide-react";
import Link from "next/link";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { useState } from "react";

import { useStorefront } from "@/components/providers/StorefrontProvider";
import { useSupabaseSession } from "@/components/providers/SupabaseSessionProvider";
import { cn } from "@/lib/utils";
import { useCartStore } from "@/store/cart";

type NavLinkItem = {
  href: string;
  key: string;
  icon: LucideIcon;
};

const NAV_LINKS: NavLinkItem[] = [
  { href: "/", key: "nav.home", icon: House },
  { href: "/products", key: "nav.products", icon: LayoutGrid },
];

function isNavActive(pathname: string, href: string) {
  if (href === "/") {
    return pathname === "/";
  }

  if (href === "/products") {
    return (
      pathname === "/products" ||
      pathname.startsWith("/product/") ||
      pathname.startsWith("/category/")
    );
  }

  return pathname === href;
}

export function Header() {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const { user } = useSupabaseSession();
  const { isRTL, t, toggleLanguage } = useStorefront();
  const totalItems = useCartStore((state) => state.totalItems);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const cartActive = pathname === "/cart";
  const accountActive = pathname.startsWith("/account") || pathname.startsWith("/auth");

  function submitSearch(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const formData = new FormData(event.currentTarget);
    const trimmed = String(formData.get("q") ?? "").trim();
    setIsMenuOpen(false);
    router.push(trimmed ? `/products?q=${encodeURIComponent(trimmed)}` : "/products");
  }

  function changeLanguage() {
    toggleLanguage();
    setIsMenuOpen(false);
    router.refresh();
  }

  return (
    <header className="sticky top-0 z-50 pt-4">
      <div className="page-shell">
        <div className="frosted rounded-[2rem] border border-white/80 px-4 py-4 shadow-soft sm:px-5">
          <div className="flex items-center justify-between gap-3">
            <div
              className={cn(
                "flex items-center gap-3",
                isRTL && "flex-row-reverse"
              )}
            >
              <button
                type="button"
                onClick={() => setIsMenuOpen((current) => !current)}
                className="inline-flex h-12 w-12 items-center justify-center rounded-[1.25rem] border border-slate-200 bg-white text-slate-700 transition hover:border-primary/30 hover:text-[#1D1D1F] lg:hidden"
                aria-label={t("nav.menu")}
              >
                {isMenuOpen ? <X size={18} /> : <Menu size={18} />}
              </button>

              <Link
                href="/"
                className={cn(
                  "inline-flex items-center gap-3 rounded-[1.6rem] bg-white px-3 py-2 shadow-soft",
                  isRTL && "flex-row-reverse"
                )}
              >
                <span className="flex h-11 w-11 items-center justify-center rounded-[1rem] bg-primary text-lg font-bold text-white shadow-button">
                  أ
                </span>
                <span className={cn("leading-tight", isRTL ? "text-right" : "text-left")}>
                  <span className="block text-sm font-semibold text-[#1D1D1F]">
                    {isRTL ? "الأمل سنتر" : "Al Amal Center"}
                  </span>
                  <span className="mt-1 block text-xs text-slate-500">
                    {isRTL ? "Al Amal Center" : "الأمل سنتر"}
                  </span>
                </span>
              </Link>
            </div>

            <div className="hidden min-w-0 flex-1 lg:block">
              <form onSubmit={submitSearch}>
                <div className="relative">
                  <Search
                    size={18}
                    className={cn(
                      "pointer-events-none absolute top-1/2 -translate-y-1/2 text-slate-400",
                      isRTL ? "right-5" : "left-5"
                    )}
                  />
                  <input
                    key={`${pathname}-${searchParams.get("q") ?? ""}-desktop`}
                    name="q"
                    defaultValue={searchParams.get("q") ?? ""}
                    placeholder={t("nav.search")}
                    className={cn(
                      "field-input bg-white/90",
                      isRTL ? "pr-14 text-right" : "pl-14 text-left"
                    )}
                  />
                </div>
              </form>
            </div>

            <div
              className={cn(
                "flex items-center gap-2 sm:gap-3",
                isRTL && "flex-row-reverse"
              )}
            >
              <nav className={cn("hidden items-center gap-2 lg:flex", isRTL && "flex-row-reverse")}>
                {NAV_LINKS.map((item) => {
                  const Icon = item.icon;
                  const active = isNavActive(pathname, item.href);

                  return (
                    <Link
                      key={item.href}
                      href={item.href}
                      aria-current={active ? "page" : undefined}
                      className={cn(
                        "inline-flex min-h-12 items-center gap-2 rounded-[1.25rem] border border-transparent px-4 text-sm font-medium transition",
                        active
                          ? "bg-[#1D1D1F] text-white shadow-soft"
                          : "bg-white text-slate-600 hover:border-primary/20 hover:text-[#1D1D1F]"
                      )}
                    >
                      <Icon size={18} />
                      <span className="hidden xl:inline">{t(item.key)}</span>
                    </Link>
                  );
                })}
              </nav>

              <button
                type="button"
                onClick={changeLanguage}
                className="inline-flex h-12 items-center gap-2 rounded-[1.25rem] border border-slate-200 bg-white px-4 text-sm font-medium text-slate-600 transition hover:border-primary/30 hover:text-[#1D1D1F]"
              >
                <Globe size={16} />
                <span className="hidden 2xl:inline">{t("nav.language")}</span>
              </button>

              <Link
                href={user ? "/account" : "/auth/login"}
                className={cn(
                  "hidden h-12 items-center gap-2 rounded-[1.25rem] border border-slate-200 bg-white px-4 text-sm font-medium transition hover:border-primary/30 hover:text-[#1D1D1F] sm:inline-flex",
                  accountActive
                    ? "border-primary/30 bg-primary/5 text-primary"
                    : "text-slate-600"
                )}
                aria-label={user ? t("nav.account") : t("nav.login")}
              >
                <UserCircle2 size={17} />
                <span className="hidden xl:inline">
                  {user ? t("nav.account") : t("nav.login")}
                </span>
              </Link>

              <Link
                href="/cart"
                className={cn(
                  "relative inline-flex h-12 w-12 items-center justify-center rounded-[1.25rem] border bg-white transition",
                  cartActive
                    ? "border-primary/30 bg-primary/5 text-primary"
                    : "border-slate-200 text-slate-700 hover:border-primary/30 hover:text-[#1D1D1F]"
                )}
                aria-label={t("nav.cart")}
              >
                <ShoppingBag size={18} />
                <span
                  className={cn(
                    "absolute -top-1 min-w-5 rounded-full bg-primary px-1.5 py-0.5 text-center text-[11px] font-bold text-white",
                    isRTL ? "-left-1" : "-right-1"
                  )}
                >
                  {totalItems}
                </span>
              </Link>
            </div>
          </div>

          <div
            className={cn(
              "overflow-hidden transition-all duration-300 lg:hidden",
              isMenuOpen ? "mt-4 max-h-[36rem]" : "max-h-0"
            )}
          >
            <div className="grid gap-3 border-t border-slate-100 pt-4">
              <form onSubmit={submitSearch}>
                <div className="relative">
                  <Search
                    size={18}
                    className={cn(
                      "pointer-events-none absolute top-1/2 -translate-y-1/2 text-slate-400",
                      isRTL ? "right-5" : "left-5"
                    )}
                  />
                  <input
                    key={`${pathname}-${searchParams.get("q") ?? ""}-mobile`}
                    name="q"
                    defaultValue={searchParams.get("q") ?? ""}
                    placeholder={t("nav.search")}
                    className={cn(
                      "field-input bg-white",
                      isRTL ? "pr-14 text-right" : "pl-14 text-left"
                    )}
                  />
                </div>
              </form>

              <div className="grid grid-cols-2 gap-3">
                {NAV_LINKS.map((item) => {
                  const Icon = item.icon;
                  const active = isNavActive(pathname, item.href);

                  return (
                    <Link
                      key={item.href}
                      href={item.href}
                      onClick={() => setIsMenuOpen(false)}
                      className={cn(
                        "flex min-h-[4.75rem] flex-col items-center justify-center gap-2 rounded-[1.5rem] border text-sm font-medium transition",
                        active
                          ? "border-primary/30 bg-primary/5 text-primary"
                          : "border-slate-200 bg-white text-slate-600 hover:text-[#1D1D1F]"
                      )}
                    >
                      <Icon size={18} />
                      <span>{t(item.key)}</span>
                    </Link>
                  );
                })}

                <Link
                  href="/cart"
                  onClick={() => setIsMenuOpen(false)}
                  className={cn(
                    "flex min-h-[4.75rem] flex-col items-center justify-center gap-2 rounded-[1.5rem] border text-sm font-medium transition",
                    cartActive
                      ? "border-primary/30 bg-primary/5 text-primary"
                      : "border-slate-200 bg-white text-slate-600 hover:text-[#1D1D1F]"
                  )}
                >
                  <ShoppingBag size={18} />
                  <span>{t("nav.cart")}</span>
                </Link>

                <Link
                  href={user ? "/account" : "/auth/login"}
                  onClick={() => setIsMenuOpen(false)}
                  className={cn(
                    "flex min-h-[4.75rem] flex-col items-center justify-center gap-2 rounded-[1.5rem] border text-sm font-medium transition",
                    accountActive
                      ? "border-primary/30 bg-primary/5 text-primary"
                      : "border-slate-200 bg-white text-slate-600 hover:text-[#1D1D1F]"
                  )}
                >
                  <UserCircle2 size={18} />
                  <span>{user ? t("nav.account") : t("nav.login")}</span>
                </Link>
              </div>

              <button
                type="button"
                onClick={changeLanguage}
                className="inline-flex min-h-12 items-center justify-center gap-2 rounded-[1.25rem] border border-slate-200 bg-white px-4 text-sm font-medium text-slate-600 transition hover:border-primary/30 hover:text-[#1D1D1F]"
              >
                <Globe size={16} />
                <span>{t("nav.language")}</span>
              </button>
            </div>
          </div>
        </div>
      </div>
    </header>
  );
}
